package com.ecommerce.search.config;

import org.apache.http.HttpHost;
import org.apache.http.auth.AuthScope;
import org.apache.http.auth.UsernamePasswordCredentials;
import org.apache.http.impl.client.BasicCredentialsProvider;
import org.apache.http.ssl.SSLContextBuilder;
import org.apache.http.ssl.SSLContexts;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestClientBuilder;
import org.elasticsearch.client.RestHighLevelClient;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.io.ResourceLoader;

import javax.net.ssl.SSLContext;
import java.io.InputStream;
import java.security.KeyStore;

@Configuration
public class ElasticsearchConfig {

    private static final Logger logger = LoggerFactory.getLogger(ElasticsearchConfig.class);

    private final ElasticsearchProperties properties;
    private final ResourceLoader resourceLoader;

    public ElasticsearchConfig(ElasticsearchProperties properties, ResourceLoader resourceLoader) {
        this.properties = properties;
        this.resourceLoader = resourceLoader;
    }

    @Bean(destroyMethod = "close")
    public RestHighLevelClient restHighLevelClient() throws Exception {
        // Enforce HTTPS scheme to prevent unencrypted communication
        String scheme = properties.getScheme();
        if (!"https".equalsIgnoreCase(scheme)) {
            logger.warn("Elasticsearch scheme was set to '{}', overriding to 'https' for security.", scheme);
            scheme = "https";
        }

        HttpHost httpHost = new HttpHost(properties.getHost(), properties.getPort(), scheme);

        // Configure credentials
        BasicCredentialsProvider credentialsProvider = new BasicCredentialsProvider();
        credentialsProvider.setCredentials(
                AuthScope.ANY,
                new UsernamePasswordCredentials(properties.getUsername(), properties.getPassword())
        );

        // Build SSL context with truststore
        SSLContext sslContext = buildSSLContext();

        RestClientBuilder builder = RestClient.builder(httpHost)
                .setHttpClientConfigCallback(httpClientBuilder -> {
                    httpClientBuilder.setDefaultCredentialsProvider(credentialsProvider);
                    httpClientBuilder.setSSLContext(sslContext);
                    return httpClientBuilder;
                })
                .setRequestConfigCallback(requestConfigBuilder ->
                        requestConfigBuilder
                                .setConnectTimeout(properties.getConnectTimeout())
                                .setSocketTimeout(properties.getSocketTimeout())
                );

        return new RestHighLevelClient(builder);
    }

    private SSLContext buildSSLContext() throws Exception {
        String truststorePath = properties.getTruststorePath();
        String truststorePassword = properties.getTruststorePassword();

        if (truststorePath != null && !truststorePath.isEmpty()) {
            KeyStore trustStore = KeyStore.getInstance("JKS");
            try (InputStream is = resourceLoader.getResource(truststorePath).getInputStream()) {
                trustStore.load(is, truststorePassword != null ? truststorePassword.toCharArray() : null);
            }
            SSLContextBuilder sslContextBuilder = SSLContexts.custom()
                    .loadTrustMaterial(trustStore, null);
            return sslContextBuilder.build();
        } else {
            // Use default SSL context with system truststore
            return SSLContexts.createDefault();
        }
    }
}

