package com.ecommerce.search.service;

import com.ecommerce.search.config.ElasticsearchProperties;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.CreateIndexResponse;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;

@Service
public class IndexManagementService {

    private static final Logger logger = LoggerFactory.getLogger(IndexManagementService.class);

    private final RestHighLevelClient client;
    private final ElasticsearchProperties properties;

    public IndexManagementService(RestHighLevelClient client, ElasticsearchProperties properties) {
        this.client = client;
        this.properties = properties;
    }

    @PostConstruct
    public void initializeIndices() {
        try {
            createProductIndexIfNotExists();
            createSearchQueryIndexIfNotExists();
            logger.info("Elasticsearch indices initialized successfully.");
        } catch (IOException e) {
            logger.error("Failed to initialize Elasticsearch indices", e);
            throw new RuntimeException("Failed to initialize Elasticsearch indices", e);
        }
    }

    private void createProductIndexIfNotExists() throws IOException {
        String indexName = properties.getIndices().getProducts();
        if (!indexExists(indexName)) {
            CreateIndexRequest request = new CreateIndexRequest(indexName);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 3)
                    .put("index.number_of_replicas", 1)
                    .put("index.max_result_window", 10000)
                    .put("analysis.analyzer.product_analyzer.type", "custom")
                    .put("analysis.analyzer.product_analyzer.tokenizer", "standard")
                    .putList("analysis.analyzer.product_analyzer.filter", "lowercase", "stop", "snowball")
            );

            String mapping = "{\n" +
                    "  \"properties\": {\n" +
                    "    \"name\": {\n" +
                    "      \"type\": \"text\",\n" +
                    "      \"analyzer\": \"product_analyzer\",\n" +
                    "      \"fields\": {\n" +
                    "        \"keyword\": { \"type\": \"keyword\" },\n" +
                    "        \"suggest\": { \"type\": \"completion\" }\n" +
                    "      }\n" +
                    "    },\n" +
                    "    \"description\": {\n" +
                    "      \"type\": \"text\",\n" +
                    "      \"analyzer\": \"product_analyzer\"\n" +
                    "    },\n" +
                    "    \"category\": {\n" +
                    "      \"type\": \"keyword\"\n" +
                    "    },\n" +
                    "    \"brand\": {\n" +
                    "      \"type\": \"keyword\"\n" +
                    "    },\n" +
                    "    \"price\": {\n" +
                    "      \"type\": \"double\"\n" +
                    "    },\n" +
                    "    \"originalPrice\": {\n" +
                    "      \"type\": \"double\"\n" +
                    "    },\n" +
                    "    \"currency\": {\n" +
                    "      \"type\": \"keyword\"\n" +
                    "    },\n" +
                    "    \"tags\": {\n" +
                    "      \"type\": \"keyword\"\n" +
                    "    },\n" +
                    "    \"attributes\": {\n" +
                    "      \"type\": \"object\",\n" +
                    "      \"enabled\": true\n" +
                    "    },\n" +
                    "    \"imageUrl\": {\n" +
                    "      \"type\": \"keyword\",\n" +
                    "      \"index\": false\n" +
                    "    },\n" +
                    "    \"rating\": {\n" +
                    "      \"type\": \"double\"\n" +
                    "    },\n" +
                    "    \"reviewCount\": {\n" +
                    "      \"type\": \"integer\"\n" +
                    "    },\n" +
                    "    \"inStock\": {\n" +
                    "      \"type\": \"boolean\"\n" +
                    "    },\n" +
                    "    \"stockQuantity\": {\n" +
                    "      \"type\": \"integer\"\n" +
                    "    },\n" +
                    "    \"sku\": {\n" +
                    "      \"type\": \"keyword\"\n" +
                    "    },\n" +
                    "    \"created_at\": {\n" +
                    "      \"type\": \"date\"\n" +
                    "    },\n" +
                    "    \"updated_at\": {\n" +
                    "      \"type\": \"date\"\n" +
                    "    }\n" +
                    "  }\n" +
                    "}";

            request.mapping(mapping, XContentType.JSON);
            CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
            logger.info("Created index '{}': acknowledged={}", indexName, response.isAcknowledged());
        }
    }

    private void createSearchQueryIndexIfNotExists() throws IOException {
        String indexName = properties.getIndices().getSearchQueries();
        if (!indexExists(indexName)) {
            CreateIndexRequest request = new CreateIndexRequest(indexName);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 2)
                    .put("index.number_of_replicas", 1)
            );

            String mapping = "{\n" +
                    "  \"properties\": {\n" +
                    "    \"query_text\": { \"type\": \"text\", \"fields\": { \"keyword\": { \"type\": \"keyword\" } } },\n" +
                    "    \"customer_id\": { \"type\": \"keyword\" },\n" +
                    "    \"session_id\": { \"type\": \"keyword\" },\n" +
                    "    \"result_count\": { \"type\": \"long\" },\n" +
                    "    \"filters\": { \"type\": \"object\" },\n" +
                    "    \"sort_field\": { \"type\": \"keyword\" },\n" +
                    "    \"sort_order\": { \"type\": \"keyword\" },\n" +
                    "    \"page\": { \"type\": \"integer\" },\n" +
                    "    \"page_size\": { \"type\": \"integer\" },\n" +
                    "    \"response_time_ms\": { \"type\": \"long\" },\n" +
                    "    \"timestamp\": { \"type\": \"date\" },\n" +
                    "    \"ip_address\": { \"type\": \"ip\" },\n" +
                    "    \"user_agent\": { \"type\": \"text\" }\n" +
                    "  }\n" +
                    "}";

            request.mapping(mapping, XContentType.JSON);
            CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
            logger.info("Created index '{}': acknowledged={}", indexName, response.isAcknowledged());
        }
    }

    public boolean indexExists(String indexName) throws IOException {
        GetIndexRequest request = new GetIndexRequest(indexName);
        return client.indices().exists(request, RequestOptions.DEFAULT);
    }

    public void deleteIndex(String indexName) throws IOException {
        if (indexExists(indexName)) {
            DeleteIndexRequest request = new DeleteIndexRequest(indexName);
            client.indices().delete(request, RequestOptions.DEFAULT);
            logger.info("Deleted index '{}'", indexName);
        }
    }
}

