import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;

@Service
public class ProductIndexingService {

    private static final Logger logger = LoggerFactory.getLogger(ProductIndexingService.class);

    private final RestHighLevelClient client;
    private final ElasticsearchProperties properties;
    private final ObjectMapper objectMapper;

    public ProductIndexingService(RestHighLevelClient client,
                                   ElasticsearchProperties properties,
                                   ObjectMapper objectMapper) {
        this.client = client;
        this.properties = properties;
        this.objectMapper = objectMapper;
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }
        product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        String jsonString = objectMapper.writeValueAsString(product);

        IndexRequest request = new IndexRequest(properties.getIndices().getProducts())
                .id(product.getId())
                .source(jsonString, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        logger.info("Indexed product '{}' with id '{}', result: {}",
                product.getName(), product.getId(), response.getResult().name());

        return product.getId();
    }

    public BulkResponse bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();

        for (Product product : products) {
            if (product.getId() == null || product.getId().isEmpty()) {
                product.setId(UUID.randomUUID().toString());
            }
            product.setCreatedAt(Instant.now());
            product.setUpdatedAt(Instant.now());

            String jsonString = objectMapper.writeValueAsString(product);

            IndexRequest indexRequest = new IndexRequest(properties.getIndices().getProducts())
                    .id(product.getId())
                    .source(jsonString, XContentType.JSON);

            bulkRequest.add(indexRequest);
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        logger.info("Bulk indexed {} products, hasFailures: {}",
                products.size(), bulkResponse.hasFailures());

        if (bulkResponse.hasFailures()) {
            logger.error("Bulk indexing failures: {}", bulkResponse.buildFailureMessage());
        }

        return bulkResponse;
    }

    public Optional<Product> getProduct(String productId) throws IOException {
        GetRequest request = new GetRequest(properties.getIndices().getProducts(), productId);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (response.isExists()) {
            Product product = objectMapper.readValue(response.getSourceAsString(), Product.class);
            product.setId(response.getId());
            return Optional.of(product);
        }
        return Optional.empty();
    }

    public UpdateResponse updateProduct(String productId, Map<String, Object> updates) throws IOException {
        updates.put("updated_at", Instant.now().toString());

        UpdateRequest request = new UpdateRequest(properties.getIndices().getProducts(), productId)
                .doc(updates);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        logger.info("Updated product '{}', result: {}", productId, response.getResult().name());
        return response;
    }

    public DeleteResponse deleteProduct(String productId) throws IOException {
        DeleteRequest request = new DeleteRequest(properties.getIndices().getProducts(), productId);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);
        logger.info("Deleted product '{}', result: {}", productId, response.getResult().name());
        return response;
    }
}

