package com.ecommerce.search.service;

import com.ecommerce.search.config.ElasticsearchProperties;
import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.dto.SearchResponse.FacetBucket;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.search.SearchRequestBuilder;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.text.Text;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private static final Logger logger = LoggerFactory.getLogger(ProductSearchService.class);

    private final RestHighLevelClient client;
    private final ElasticsearchProperties properties;
    private final ObjectMapper objectMapper;
    private final SearchQueryLoggingService searchQueryLoggingService;

    public ProductSearchService(RestHighLevelClient client,
                                 ElasticsearchProperties properties,
                                 ObjectMapper objectMapper,
                                 SearchQueryLoggingService searchQueryLoggingService) {
        this.client = client;
        this.properties = properties;
        this.objectMapper = objectMapper;
        this.searchQueryLoggingService = searchQueryLoggingService;
    }

    public SearchResponse search(SearchRequest searchRequest) throws IOException {
        long startTime = System.currentTimeMillis();

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(properties.getIndices().getProducts());

        SearchSourceBuilder sourceBuilder = buildSearchQuery(searchRequest);
        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
                client.search(esRequest, RequestOptions.DEFAULT);

        long responseTimeMs = System.currentTimeMillis() - startTime;

        SearchResponse response = buildSearchResponse(esResponse, searchRequest, responseTimeMs);

        // Log the search query asynchronously
        logSearchQuery(searchRequest, response, responseTimeMs);

        return response;
    }

    private SearchSourceBuilder buildSearchQuery(SearchRequest searchRequest) {
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search
        if (searchRequest.getQuery() != null && !searchRequest.getQuery().trim().isEmpty()) {
            MultiMatchQueryBuilder multiMatchQuery = QueryBuilders.multiMatchQuery(
                    searchRequest.getQuery(),
                    "name^3", "description^1", "brand^2", "tags^1.5", "category^2"
            )
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO)
                    .minimumShouldMatch("75%");

            boolQuery.must(multiMatchQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        // Category filter
        if (searchRequest.getCategory() != null && !searchRequest.getCategory().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("category", searchRequest.getCategory()));
        }
        if (searchRequest.getCategories() != null && !searchRequest.getCategories().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("category", searchRequest.getCategories()));
        }

        // Brand filter
        if (searchRequest.getBrand() != null && !searchRequest.getBrand().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", searchRequest.getBrand()));
        }
        if (searchRequest.getBrands() != null && !searchRequest.getBrands().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("brand", searchRequest.getBrands()));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                rangeQuery.gte(searchRequest.getMinPrice());
            }
            if (searchRequest.getMaxPrice() != null) {
                rangeQuery.lte(searchRequest.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // In stock filter
        if (searchRequest.getInStock() != null) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", searchRequest.getInStock()));
        }

        // Attribute filters
        if (searchRequest.getAttributeFilters() != null) {
            for (Map.Entry<String, String> entry : searchRequest.getAttributeFilters().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + entry.getKey(), entry.getValue()));
            }
        }

        sourceBuilder.query(boolQuery);

        // Pagination
        sourceBuilder.from(searchRequest.getPage() * searchRequest.getPageSize());
        sourceBuilder.size(searchRequest.getPageSize());

        // Sorting
        applySorting(sourceBuilder, searchRequest);

        // Highlighting
        HighlightBuilder highlightBuilder = new HighlightBuilder()
                .field("name")
                .field("description")
                .preTags("<em>")
                .postTags("</em>")
                .fragmentSize(150)
                .numOfFragments(3);
        sourceBuilder.highlighter(highlightBuilder);

        // Faceted aggregations
        addFacetAggregations(sourceBuilder);

        return sourceBuilder;
    }

    private void applySorting(SearchSourceBuilder sourceBuilder, SearchRequest searchRequest) {
        String sortField = searchRequest.getSortField();
        SortOrder sortOrder = "asc".equalsIgnoreCase(searchRequest.getSortOrder())
                ? SortOrder.ASC : SortOrder.DESC;

        switch (sortField != null ? sortField.toLowerCase() : "relevance") {
            case "price":
                sourceBuilder.sort("price", sortOrder);
                break;
            case "rating":
                sourceBuilder.sort("rating", sortOrder);
                break;
            case "name":
                sourceBuilder.sort("name.keyword", sortOrder);
                break;
            case "newest":
                sourceBuilder.sort("created_at", SortOrder.DESC);
                break;
            case "review_count":
                sourceBuilder.sort("reviewCount", sortOrder);
                break;
            case "relevance":
            default:
                // Use default relevance scoring
                break;
        }
    }

    private void addFacetAggregations(SearchSourceBuilder sourceBuilder) {
        // Category facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("categories")
                        .field("category")
                        .size(50)
        );

        // Brand facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("brands")
                        .field("brand")
                        .size(50)
        );

        // Price range facet
        sourceBuilder.aggregation(
                AggregationBuilders.range("price_ranges")
                        .field("price")
                        .addUnboundedTo("Under $25", 25)
                        .addRange("$25 - $50", 25, 50)
                        .addRange("$50 - $100", 50, 100)
                        .addRange("$100 - $200", 100, 200)
                        .addRange("$200 - $500", 200, 500)
                        .addUnboundedFrom("$500+", 500)
        );

        // Rating facet
        sourceBuilder.aggregation(
                AggregationBuilders.range("ratings")
                        .field("rating")
                        .addRange("4+ Stars", 4, 5.01)
                        .addRange("3+ Stars", 3, 5.01)
                        .addRange("2+ Stars", 2, 5.01)
                        .addRange("1+ Stars", 1, 5.01)
        );

        // Tags facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("tags")
                        .field("tags")
                        .size(30)
        );

        // In stock facet
        sourceBuilder.aggregation(
                AggregationBuilders.terms("availability")
                        .field("inStock")
        );
    }

    private SearchResponse buildSearchResponse(org.elasticsearch.action.search.SearchResponse esResponse,
                                                SearchRequest searchRequest,
                                                long responseTimeMs) throws IOException {
        SearchResponse response = new SearchResponse();

        // Parse products
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : esResponse.getHits().getHits()) {
            Product product = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            product.setId(hit.getId());
            products.add(product);
        }
        response.setProducts(products);

        // Total hits
        long totalHits = esResponse.getHits().getTotalHits().value;
        response.setTotalHits(totalHits);
        response.setPage(searchRequest.getPage());
        response.setPageSize(searchRequest.getPageSize());
        response.setTotalPages((int) Math.ceil((double) totalHits / searchRequest.getPageSize()));
        response.setResponseTimeMs(responseTimeMs);

        // Parse facets
        Map<String, List<FacetBucket>> facets = new LinkedHashMap<>();

        if (esResponse.getAggregations() != null) {
            // Category facet
            Terms categoryTerms = esResponse.getAggregations().get("categories");
            if (categoryTerms != null) {
                facets.put("categories", categoryTerms.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            // Brand facet
            Terms brandTerms = esResponse.getAggregations().get("brands");
            if (brandTerms != null) {
                facets.put("brands", brandTerms.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            // Price ranges facet
            Range priceRanges = esResponse.getAggregations().get("price_ranges");
            if (priceRanges != null) {
                facets.put("price_ranges", priceRanges.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            // Rating facet
            Range ratings = esResponse.getAggregations().get("ratings");
            if (ratings != null) {
                facets.put("ratings", ratings.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            // Tags facet
            Terms tagTerms = esResponse.getAggregations().get("tags");
            if (tagTerms != null) {
                facets.put("tags", tagTerms.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            // Availability facet
            Terms availabilityTerms = esResponse.getAggregations().get("availability");
            if (availabilityTerms != null) {
                facets.put("availability", availabilityTerms.getBuckets().stream()
                        .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }
        }

        response.setFacets(facets);

        return response;
    }

    public List<String> suggest(String prefix) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(properties.getIndices().getProducts());

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        SuggestBuilder suggestBuilder = new SuggestBuilder();
        suggestBuilder.addSuggestion("product-suggest",
                SuggestBuilders.completionSuggestion("name.suggest")
                        .prefix(prefix, Fuzziness.AUTO)
                        .size(10)
        );
        sourceBuilder.suggest(suggestBuilder);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
                client.search(esRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        if (esResponse.getSuggest() != null) {
            CompletionSuggestion suggestion = esResponse.getSuggest().getSuggestion("product-suggest");
            if (suggestion != null) {
                for (CompletionSuggestion.Entry entry : suggestion.getEntries()) {
                    for (CompletionSuggestion.Entry.Option option : entry.getOptions()) {
                        suggestions.add(option.getText().string());
                    }
                }
            }
        }

        return suggestions;
    }

    private void logSearchQuery(SearchRequest searchRequest, SearchResponse response, long responseTimeMs) {
        try {
            SearchQuery searchQuery = new SearchQuery();
            searchQuery.setId(UUID.randomUUID().toString());
            searchQuery.setQueryText(searchRequest.getQuery());
            searchQuery.setCustomerId(searchRequest.getCustomerId());
            searchQuery.setSessionId(searchRequest.getSessionId());
            searchQuery.setResultCount(response.getTotalHits());
            searchQuery.setFilters(searchRequest.getAttributeFilters());
            searchQuery.setSortField(searchRequest.getSortField());
            searchQuery.setSortOrder(searchRequest.getSortOrder());
            searchQuery.setPage(searchRequest.getPage());
            searchQuery.setPageSize(searchRequest.getPageSize());
            searchQuery.setResponseTimeMs(responseTimeMs);
            searchQuery.setTimestamp(Instant.now());

            searchQueryLoggingService.logSearchQuery(searchQuery);
        } catch (Exception e) {
            logger.warn("Failed to log search query", e);
        }
    }
}

