package com.ecommerce.search.service;

import com.ecommerce.search.config.ElasticsearchProperties;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.LinkedHashMap;
import java.util.Map;

@Service
public class SearchQueryLoggingService {

    private static final Logger logger = LoggerFactory.getLogger(SearchQueryLoggingService.class);

    private final RestHighLevelClient client;
    private final ElasticsearchProperties properties;
    private final ObjectMapper objectMapper;

    public SearchQueryLoggingService(RestHighLevelClient client,
                                      ElasticsearchProperties properties,
                                      ObjectMapper objectMapper) {
        this.client = client;
        this.properties = properties;
        this.objectMapper = objectMapper;
    }

    @Async
    public void logSearchQuery(SearchQuery searchQuery) {
        try {
            String jsonString = objectMapper.writeValueAsString(searchQuery);

            IndexRequest request = new IndexRequest(properties.getIndices().getSearchQueries())
                    .id(searchQuery.getId())
                    .source(jsonString, XContentType.JSON);

            IndexResponse response = client.index(request, RequestOptions.DEFAULT);
            logger.debug("Logged search query '{}', result: {}",
                    searchQuery.getQueryText(), response.getResult().name());
        } catch (IOException e) {
            logger.error("Failed to log search query", e);
        }
    }

    public Map<String, Long> getTopSearchQueries(int size) throws IOException {
        SearchRequest searchRequest = new SearchRequest(properties.getIndices().getSearchQueries());

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);
        sourceBuilder.aggregation(
                AggregationBuilders.terms("top_queries")
                        .field("query_text.keyword")
                        .size(size)
        );

        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        Map<String, Long> topQueries = new LinkedHashMap<>();
        Terms terms = response.getAggregations().get("top_queries");
        if (terms != null) {
            for (Terms.Bucket bucket : terms.getBuckets()) {
                topQueries.put(bucket.getKeyAsString(), bucket.getDocCount());
            }
        }

        return topQueries;
    }

    public Map<String, Long> getZeroResultQueries(int size) throws IOException {
        SearchRequest searchRequest = new SearchRequest(properties.getIndices().getSearchQueries());

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);
        sourceBuilder.query(QueryBuilders.termQuery("result_count", 0));
        sourceBuilder.aggregation(
                AggregationBuilders.terms("zero_result_queries")
                        .field("query_text.keyword")
                        .size(size)
        );

        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        Map<String, Long> zeroResultQueries = new LinkedHashMap<>();
        Terms terms = response.getAggregations().get("zero_result_queries");
        if (terms != null) {
            for (Terms.Bucket bucket : terms.getBuckets()) {
                zeroResultQueries.put(bucket.getKeyAsString(), bucket.getDocCount());
            }
        }

        return zeroResultQueries;
    }
}

