package com.ecommerce.search.controller;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.io.IOException;
import java.util.List;
import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexingService productIndexingService;

    public ProductController(ProductIndexingService productIndexingService) {
        this.productIndexingService = productIndexingService;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@Valid @RequestBody Product product) throws IOException {
        String id = productIndexingService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("id", id, "message", "Product indexed successfully"));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, Object>> bulkIndexProducts(@Valid @RequestBody List<Product> products) throws IOException {
        var bulkResponse = productIndexingService.bulkIndexProducts(products);
        return ResponseEntity.ok(Map.of(
                "indexed", products.size(),
                "hasFailures", bulkResponse.hasFailures(),
                "took_ms", bulkResponse.getTook().getMillis()
        ));
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Optional<Product> product = productIndexingService.getProduct(id);
        return product.map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @PatchMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(
            @PathVariable String id,
            @RequestBody Map<String, Object> updates) throws IOException {
        productIndexingService.updateProduct(id, updates);
        return ResponseEntity.ok(Map.of("message", "Product updated successfully"));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) throws IOException {
        productIndexingService.deleteProduct(id);
        return ResponseEntity.ok(Map.of("message", "Product deleted successfully"));
    }
}

