package com.ecommerce.search.controller;

import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.service.ProductSearchService;
import com.ecommerce.search.service.SearchQueryLoggingService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/search")
public class SearchController {

    private final ProductSearchService productSearchService;
    private final SearchQueryLoggingService searchQueryLoggingService;

    public SearchController(ProductSearchService productSearchService,
                             SearchQueryLoggingService searchQueryLoggingService) {
        this.productSearchService = productSearchService;
        this.searchQueryLoggingService = searchQueryLoggingService;
    }

    @PostMapping
    public ResponseEntity<SearchResponse> search(@Valid @RequestBody SearchRequest searchRequest) throws IOException {
        SearchResponse response = productSearchService.search(searchRequest);
        return ResponseEntity.ok(response);
    }

    @GetMapping
    public ResponseEntity<SearchResponse> searchGet(
            @RequestParam(required = false) String query,
            @RequestParam(required = false) String category,
            @RequestParam(required = false) String brand,
            @RequestParam(required = false) Double minPrice,
            @RequestParam(required = false) Double maxPrice,
            @RequestParam(required = false) Double minRating,
            @RequestParam(required = false) Boolean inStock,
            @RequestParam(defaultValue = "relevance") String sortField,
            @RequestParam(defaultValue = "desc") String sortOrder,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "20") int pageSize) throws IOException {

        SearchRequest searchRequest = new SearchRequest();
        searchRequest.setQuery(query);
        searchRequest.setCategory(category);
        searchRequest.setBrand(brand);
        if (minPrice != null) searchRequest.setMinPrice(java.math.BigDecimal.valueOf(minPrice));
        if (maxPrice != null) searchRequest.setMaxPrice(java.math.BigDecimal.valueOf(maxPrice));
        searchRequest.setMinRating(minRating);
        searchRequest.setInStock(inStock);
        searchRequest.setSortField(sortField);
        searchRequest.setSortOrder(sortOrder);
        searchRequest.setPage(page);
        searchRequest.setPageSize(pageSize);

        SearchResponse response = productSearchService.search(searchRequest);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/suggest")
    public ResponseEntity<List<String>> suggest(@RequestParam String prefix) throws IOException {
        List<String> suggestions = productSearchService.suggest(prefix);
        return ResponseEntity.ok(suggestions);
    }

    @GetMapping("/analytics/top-queries")
    public ResponseEntity<Map<String, Long>> getTopSearchQueries(
            @RequestParam(defaultValue = "20") int size) throws IOException {
        Map<String, Long> topQueries = searchQueryLoggingService.getTopSearchQueries(size);
        return ResponseEntity.ok(topQueries);
    }

    @GetMapping("/analytics/zero-results")
    public ResponseEntity<Map<String, Long>> getZeroResultQueries(
            @RequestParam(defaultValue = "20") int size) throws IOException {
        Map<String, Long> zeroResultQueries = searchQueryLoggingService.getZeroResultQueries(size);
        return ResponseEntity.ok(zeroResultQueries);
    }
}

// ============================================================
// GlobalExceptionHandler.java
// ============================================================
package com.ecommerce.search.controller;

import org.elasticsearch.ElasticsearchException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.io.IOException;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ElasticsearchException.class)
    public ResponseEntity<Map<String, String>> handleElasticsearchException(ElasticsearchException e) {
        logger.error("Elasticsearch error", e);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(Map.of("error", "Search service error", "message", e.getMessage()));
    }

    @ExceptionHandler(IOException.class)
    public ResponseEntity<Map<String, String>> handleIOException(IOException e) {
        logger.error("IO error communicating with Elasticsearch", e);
        return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE)
                .body(Map.of("error", "Search service unavailable", "message", "Unable to connect to search backend"));
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, String>> handleValidationException(MethodArgumentNotValidException e) {
        String message = e.getBindingResult().getFieldErrors().stream()
                .map(fe -> fe.getField() + ": " + fe.getDefaultMessage())
                .reduce((a, b) -> a + "; " + b)
                .orElse("Validation error");
        return ResponseEntity.badRequest()
                .body(Map.of("error", "Validation error", "message", message));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, String>> handleGenericException(Exception e) {
        logger.error("Unexpected error", e);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(Map.of("error", "Internal server error", "message", "An unexpected error occurred"));
    }
}

